html.css:
.hero { padding: 4rem 1.5rem; background: linear-gradient(180deg, #f8f5ef 0%, #fff 100%); }
.hero h1 { font-size: clamp(2rem, 5vw, 3.25rem); color: #1e3560; margin-bottom: 1rem; }
.hero .lead { font-size: 1.125rem; color: #475467; max-width: 42rem; }
.cta-link { display: inline-block; margin-top: 1.5rem; padding: 0.75rem 1.25rem; background: #1e3560; color: #fff; text-decoration: none; border-radius: 0.375rem; }
.form-wrap { padding: 3rem 1.5rem; max-width: 40rem; margin: 0 auto; }
@media (max-width: 640px) { .hero { padding: 2.5rem 1rem; } }
